// 1. Pega a mensagem padronizada
let msg = $('SET: Padroniza Midias para Texto').first().json.Mensagem || "";

// Converte para minúsculo
msg = msg.toLowerCase();

// 2. Dicionário de tradução (Palavra -> Número)
const mapa = {
    'um': '1', 'uma': '1', 'primeira': '1', 'primeiro': '1',
    'dois': '2', 'duas': '2', 'segunda': '2', 'segundo': '2',
    'tres': '3', 'três': '3', 'terceira': '3', 'terceiro': '3',
    'quatro': '4', 'quarta': '4', 'quarto': '4',
    'cinco': '5', 'quinta': '5', 'quinto': '5',
    'seis': '6', 'sexta': '6', 'sexto': '6', 'meia': '6',
    'sete': '7', 'setima': '7', 'setimo': '7',
    'oito': '8', 'oitava': '8', 'oitavo': '8',
    'nove': '9', 'nona': '9', 'nono': '9',
    'dez': '10', 'onze': '11', 'doze': '12' // Adicionado prevenção futura
};

// Substitui palavras por números
for (let palavra in mapa) {
    let regex = new RegExp(`\\b${palavra}\\b`, 'g');
    msg = msg.replace(regex, mapa[palavra]);
}

// -----------------------------------------------------------
// CORREÇÃO DO PROBLEMA (11, 22...)
// -----------------------------------------------------------

// \b  -> Word Boundary (Garante que é um numero isolado)
// \d+ -> Um ou mais dígitos (Pega "1", "10", "11", "200")
const numeroEncontrado = msg.match(/\b\d+\b/);

// Se achou, substitui a mensagem pelo número INTEIRO encontrado.
// Ex: Se msg for "quero a 11", numeroEncontrado será "11".
if (numeroEncontrado) {
    msg = numeroEncontrado[0];
}

// Retorna o objeto
return {
    Mensagem: msg
};

