    // Garante que existe um emoji, senão usa o número puro
    const icone = emojis[cat.codigo_menu] || cat.codigo_menu;

    // Concatena (+=) a nova linha no texto
    menuTexto += `${icone} - *${cat.nome}*\n`;
}

menuTexto += "\nResponda com o número da opção desejada ou envie um áudio.";

// Retorna apenas 1 item contendo o texto completo para o envio
return [{
    json: {
        menu_dinamico: menuTexto
    }
}];
